"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Contexts
// ---------------------------------------------------------------------------

interface StepperContextValue {
  value: number
  onValueChange?: (value: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper(): StepperContextValue {
  const ctx = React.useContext(StepperContext)
  if (!ctx) throw new Error("useStepper must be used within a <Stepper>")
  return ctx
}

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem(): StepperItemContextValue {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx)
    throw new Error("useStepperItem must be used within a <StepperItem>")
  return ctx
}

// ---------------------------------------------------------------------------
// Stepper
// ---------------------------------------------------------------------------

interface StepperProps extends React.ComponentProps<"div"> {
  /** The controlled active step (1-based). */
  value?: number
  /** The initial active step when uncontrolled. Defaults to 1. */
  defaultValue?: number
  /** Called when the active step changes. */
  onValueChange?: (value: number) => void
  /** Layout direction of the step list. Defaults to "horizontal". */
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  value,
  defaultValue = 1,
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [localValue, setLocalValue] = React.useState(defaultValue)
  const controlled = value !== undefined
  const resolvedValue = controlled ? value : localValue

  const handleValueChange = React.useCallback(
    (next: number) => {
      if (!controlled) setLocalValue(next)
      onValueChange?.(next)
    },
    [controlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value: resolvedValue, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** The step number this item represents (1-based). */
  step: number
  /** When true the item is non-interactive and visually dimmed. */
  disabled?: boolean
}

function StepperItem({ step, disabled, className, ...props }: StepperItemProps) {
  const { value, orientation } = useStepper()
  const isActive = step === value
  const isCompleted = step < value

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-state={
          isCompleted ? "completed" : isActive ? "active" : "upcoming"
        }
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex flex-col",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, isActive, isCompleted } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={
        isCompleted ? "completed" : isActive ? "active" : "upcoming"
      }
      onClick={() => onValueChange?.(step)}
      className={cn(
        "flex cursor-pointer items-start gap-3 rounded-md text-left outline-none transition-all",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {/* Step indicator circle */}
      <span
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
          isCompleted
            ? "border-primary bg-primary text-primary-foreground"
            : isActive
              ? "border-primary bg-background text-primary"
              : "border-muted-foreground/40 text-muted-foreground"
        )}
      >
        {isCompleted ? (
          <CheckIcon className="size-4" />
        ) : (
          <span>{step}</span>
        )}
      </span>
      {children && (
        <div className="flex flex-col gap-0.5">{children}</div>
      )}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { isActive, isCompleted } = useStepperItem()
  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "text-sm font-medium leading-none",
        isActive || isCompleted ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  return (
    <div
      data-slot="stepper-separator"
      aria-hidden="true"
      className={cn(
        "shrink-0 bg-border transition-colors",
        orientation === "horizontal"
          ? // Horizontal: thin line aligned with circle centre (mt = half of size-8)
            "mt-4 h-px min-w-8 flex-1"
          : // Vertical: thin line aligned with circle centre (ms = half of size-8)
            "ms-4 w-px min-h-6 self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent
// ---------------------------------------------------------------------------

function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { isActive } = useStepperItem()

  if (!isActive) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn(
        "text-sm text-muted-foreground",
        // Indent content to align with the text beside the indicator circle
        // size-8 (32px) + gap-3 (12px) = 44px = ps-11
        orientation === "vertical" && "ps-11 pt-1.5",
        orientation === "horizontal" && "pt-2",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
}

