"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Create account",
    description: "Enter your credentials",
    content:
      "Fill in your name, email address, and choose a secure password to get started with your new account.",
  },
  {
    step: 2,
    title: "Verify email",
    description: "Check your inbox",
    content:
      "We've sent a verification link to your email address. Please click the link to confirm your account.",
  },
  {
    step: 3,
    title: "Complete setup",
    description: "Personalize your profile",
    content:
      "You're almost done! Add a profile photo and set your preferences to finish setting up your account.",
  },
]

export default function StepperDemo() {
  const [current, setCurrent] = React.useState(1)

  return (
    <div className="flex w-full max-w-xl flex-col gap-6">
      <Stepper value={current} onValueChange={setCurrent}>
        {steps.map((item, index) => (
          <React.Fragment key={item.step}>
            <StepperItem step={item.step}>
              <StepperTrigger>
                <StepperTitle>{item.title}</StepperTitle>
                <StepperDescription>{item.description}</StepperDescription>
              </StepperTrigger>
            </StepperItem>
            {index < steps.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>

      <div className="rounded-lg border p-4 text-sm text-muted-foreground">
        {steps.find((s) => s.step === current)?.content}
      </div>

      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setCurrent((s) => Math.max(1, s - 1))}
          disabled={current === 1}
        >
          Back
        </Button>
        <Button
          onClick={() => setCurrent((s) => Math.min(steps.length, s + 1))}
          disabled={current === steps.length}
        >
          {current === steps.length ? "Finish" : "Continue"}
        </Button>
      </div>
    </div>
  )
}

